document.addEventListener("DOMContentLoaded",function(){location.pathname.startsWith("/redirect/go/")||document.addEventListener("click",function(t){const e=t.target.closest("a");if(!e||!e.href)return;if(e.hostname===location.hostname||e.href.startsWith("#")||"tel:"===e.protocol||"mailto:"===e.protocol)return;t.preventDefault();const o=encodeURIComponent(e.href);window.location.href="/redirect/go/"+o})});